#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin >> n;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    vector<vector<int>> res;
    vector<int> path;
    function<void(int, vector<int>)> backtrack = [&](int start, vector<int> path){
        res.push_back(path);
        for(int i = start; i < n; i++){
            path.push_back(nums[i]);
            backtrack(i + 1, path);
            path.pop_back();
        }
    };
    backtrack(0, path);
    cout << res.size() << endl;
    for(auto& subset : res){
        cout << '[';
        for(int i = 0; i < subset.size(); i++){
            cout << subset[i];
            if(i != subset.size() - 1) cout << ' ';
        }
        cout << ']' << endl;
    }
    return 0;
}
